#include <bits/stdc++.h>
using namespace std;
int d(int s)
{
    for(int i=2;i<s;i++)
    {
        if(s%i==0)
        {
            return 0;
        }
    }
    return s;
}
int main()
{
    int n;
    cin>>n;
    long long s;
    for(int i=0;i<n;i++)
    {
        cin>>s;
        long long a=d(s);
        if(a!=0)
        {
            cout<<a;
        }
    }
    return 0;
}
